form:Form.form:Scripts:
		function AddAuto()
{                                
	if (Ctrl("oi_detalle_pres").GetXValue()=="")
		return;

	var param='<DATA oi_detalle_pres="'+Ctrl("oi_detalle_pres").GetXValue()+'" oi_empresa="'+Ctrl("oi_empresa").GetXValue()+'" />';
	var RS=GetProxy().SQLService().GetXML(Ctrl('main').getResource("LIQAUTO"), param);

	for (var cur=RS.FirstChild(); cur!=null; cur=cur.Next())
	{      
		if (Ctrl("LIST").ID2IDX(cur.GetAttr("oi_liquidacion"))==-1)
		{
			Ctrl("LIST").AddNew();
			Ctrl("LIST").SetCellXValue("oi_liquidacion",Ctrl("LIST").SelectedRowIDX(),cur.GetAttr("oi_liquidacion"));
		}
	}
}   

function NEXT()
{               
	if (Ctrl("LIST").RowsCount()==0)
	{             
		alert("La Liquidación es Requerida.");
		return false;
	}      


	for (t=0; t<Ctrl("LIST").RowsCount(); t++)
		if (Ctrl("LIST").GetCellXValue("oi_liquidacion",t)=="")
		{
			alert("La Liquidación es Requerida.");
			return false;
		}

	return true;
}
